const result = $input.first().json;
const assetId = $('Normalize Input').first().json.asset_id;
const engId = $('Normalize Input').first().json.engagement_id;
const assetVal = $('Normalize Input').first().json.asset_value;
const scanJobId = $('Create Scan Job').first().json.id;

// Handle screenshot API response (varies by provider)
const screenshotUrl = result.url || result.screenshot_url || result.signed_url || null;
const storageRef = screenshotUrl ? `screenshot:${assetVal}:${new Date().toISOString().split('T')[0]}` : null;

return [{ json: {
  asset_id: assetId,
  engagement_id: engId,
  asset_value: assetVal,
  scan_job_id: scanJobId,
  screenshot_url: screenshotUrl,
  storage_ref: storageRef,
  captured_at: new Date().toISOString(),
  success: !!screenshotUrl
} }];
